import java.util.*;

public class Prims {
    static int primsMST(int V, List<int[]>[] adj) {
        boolean[] visited = new boolean[V];
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
        pq.offer(new int[]{0, 0}); // {weight, vertex}
        int totalWeight = 0;

        while (!pq.isEmpty()) {
            int[] curr = pq.poll();
            int w = curr[0], u = curr[1];
            if (visited[u]) continue;
            visited[u] = true;
            totalWeight += w;
            for (int[] edge : adj[u]) {
                int v = edge[0], wt = edge[1];
                if (!visited[v]) pq.offer(new int[]{wt, v});
            }
        }
        return totalWeight;
    }

    public static void main(String[] args) {
        int V = 5;
        List<int[]>[] adj = new List[V];
        for (int i = 0; i < V; i++) adj[i] = new ArrayList<>();
        // Graph: 0-1(2), 0-3(6), 1-2(3), 1-3(8), 1-4(5), 2-4(7), 3-4(9)
        int[][] edges = {{0,1,2},{0,3,6},{1,2,3},{1,3,8},{1,4,5},{2,4,7},{3,4,9}};
        for (int[] e : edges) {
            adj[e[0]].add(new int[]{e[1], e[2]});
            adj[e[1]].add(new int[]{e[0], e[2]});
        }
        System.out.println("MST weight: " + primsMST(V, adj)); // 16
    }
}

import java.util.*;

public class Kruskals {
    static int[] parent, rank;

    static int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]); // path compression
        return parent[x];
    }

    static boolean union(int x, int y) {
        int px = find(x), py = find(y);
        if (px == py) return false;
        if (rank[px] < rank[py]) { int t = px; px = py; py = t; }
        parent[py] = px;
        if (rank[px] == rank[py]) rank[px]++;
        return true;
    }

    static int kruskalMST(int V, int[][] edges) {
        parent = new int[V]; rank = new int[V];
        for (int i = 0; i < V; i++) parent[i] = i;
        Arrays.sort(edges, Comparator.comparingInt(e -> e[2])); // sort by weight
        int totalWeight = 0, edgeCount = 0;
        for (int[] e : edges) {
            if (union(e[0], e[1])) {
                totalWeight += e[2];
                if (++edgeCount == V - 1) break; // MST complete
            }
        }
        return totalWeight;
    }

    public static void main(String[] args) {
        int V = 5;
        int[][] edges = {{0,1,2},{0,3,6},{1,2,3},{1,3,8},{1,4,5},{2,4,7},{3,4,9}};
        System.out.println("MST weight: " + kruskalMST(V, edges)); // 16
    }
}
